def add(num1: float, num2: float) -> float:
    '''Add two numbers'''
    return num1 + num2

def subtract(num1: float, num2: float) -> float:
    '''Subtract two numbers'''
    return num1 - num2

def multiply(num1: float, num2: float) -> float:
    '''Multiply two numbers'''
    return num1 * num2

def divide(num1: float, num2: float) -> float:
    '''Divide two numbers'''
    if num2 == 0:
        raise ZeroDivisionError('Cannot divide by zero')
    return num1 / num2

from flask import Blueprint, request, jsonify
from calculator import add, subtract, multiply, divide

calculator_routes = Blueprint('calculator_routes', __name__)

@calculator_routes.route('/add', methods=['POST'])
def add_route():
    try:
        num1 = float(request.json['num1'])
        num2 = float(request.json['num2'])
        result = add(num1, num2)
        return jsonify({'result': result})
    except KeyError:
        return jsonify({'error': 'Invalid input'}), 400
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@calculator_routes.route('/subtract', methods=['POST'])
def subtract_route():
    try:
        num1 = float(request.json['num1'])
        num2 = float(request.json['num2'])
        result = subtract(num1, num2)
        return jsonify({'result': result})
    except KeyError:
        return jsonify({'error': 'Invalid input'}), 400
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@calculator_routes.route('/multiply', methods=['POST'])
def multiply_route():
    try:
        num1 = float(request.json['num1'])
        num2 = float(request.json['num2'])
        result = multiply(num1, num2)
        return jsonify({'result': result})
    except KeyError:
        return jsonify({'error': 'Invalid input'}), 400
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@calculator_routes.route('/divide', methods=['POST'])
def divide_route():
    try:
        num1 = float(request.json['num1'])
        num2 = float(request.json['num2'])
        result = divide(num1, num2)
        return jsonify({'result': result})
    except KeyError:
        return jsonify({'error': 'Invalid input'}), 400
    except ZeroDivisionError as e:
        return jsonify({'error': str(e)}), 400
    except Exception as e:
        return jsonify({'error': str(e)}), 500
